import c from"llrt:hex";describe("llrt:hex",()=>{it("should encode/decode text",()=>{let t="hello",e=new TextEncoder().encode(t),o=new TextDecoder().decode(e);expect(o).toEqual(t)}),it("should encode/decode hex",()=>{let t=new TextEncoder().encode("hello"),e=c.encode(t);expect(e).toEqual("68656c6c6f")})});describe("atoa & btoa",()=>{it("btoa/atob",()=>{let t="Hello, world!",e=btoa(t);expect(e).toEqual("SGVsbG8sIHdvcmxkIQ==");let o=atob(e);expect(o).toEqual(t)})});describe("TextDecoder",()=>{it("should be able to decode UTF-16LE labels",()=>{let t=new Uint8Array([72,0,172,32,108,0,108,0,111,0,32,0,119,0,111,0,114,0,108,0,100,0,33,0]),e=new TextDecoder("UTF-16LE");expect(e.encoding).toEqual("utf-16le"),expect(e.decode(t)).toEqual("H\u20ACllo world!")}),it("should not be removed BOM",()=>{let e=new Uint8Array([239,187,191,240,159,152,132]);expect(new TextDecoder("utf8").decode(e)).toEqual("\u{1F604}");let o=new TextDecoder("utf8",{ignoreBOM:!0});expect(o.encoding).toEqual("utf-8"),expect(o.ignoreBOM).toBeTruthy();let n=new TextEncoder().encode(o.decode(e));expect(n).toEqual(e)}),it("should be generated fatal error",()=>{let t=new Uint8Array([255,254,253]);try{let e=new TextDecoder("utf-8",{fatal:!0});expect(e.fatal).toBeTruthy();let o=e.decode(t)}catch(e){expect(e.message).toEqual("invalid utf-8 sequence of 1 bytes from index 0")}}),it("should be generated unsupported error",()=>{try{let t=new TextDecoder("nonexistent_label")}catch(t){expect(t.message).toEqual('The "nonexistent_label" encoding is not supported')}})});describe("TextEncoder",()=>{it("should be able to encodeInto of surrogate pair character(Short Array)",()=>{let e=new TextEncoder,o=new Uint8Array(3),n=e.encodeInto("\u{1F525}",o);expect(n.read).toEqual(0),expect(n.written).toEqual(0),expect(o).toEqual(new Uint8Array([0,0,0]))}),it("should be able to encodeInto of surrogate pair character(Equal Length Array)",()=>{let e=new TextEncoder,o=new Uint8Array(4),n=e.encodeInto("\u{1F525}",o);expect(n.read).toEqual(2),expect(n.written).toEqual(4),expect(o).toEqual(new Uint8Array([240,159,148,165]))}),it("should be able to encodeInto of surrogate pair character(Long Array)",()=>{let e=new TextEncoder,o=new Uint8Array(5),n=e.encodeInto("\u{1F525}",o);expect(n.read).toEqual(2),expect(n.written).toEqual(4),expect(o).toEqual(new Uint8Array([240,159,148,165,0]))}),it("should be able to encodeInto and decode",()=>{let t="hono - [\u708E] means flame\u{1F525} in Japanese",e=new TextEncoder,o=new Uint8Array(40),n=e.encodeInto(t,o);expect(n.read).toEqual(36),expect(n.written).toEqual(40),expect(o).toEqual(new Uint8Array([104,111,110,111,32,45,32,91,231,130,142,93,32,109,101,97,110,115,32,102,108,97,109,101,240,159,148,165,32,105,110,32,74,97,112,97,110,101,115,101])),expect(new TextDecoder().decode(o)).toEqual(t)})});
